#!/bin/bash

# Patch the nginx configmap to add health endpoint routes

kubectl patch configmap nginx-config -n bookmyevent --type merge -p '
{
  "data": {
    "nginx.conf": "events {\n    worker_connections 1024;\n}\n\nhttp {\n    upstream user-service {\n        server user-service:8081;\n    }\n\n    upstream event-service {\n        server event-service:8082;\n    }\n\n    upstream search-service {\n        server search-service:8083;\n    }\n\n    upstream booking-service {\n        server booking-service:8084;\n    }\n\n    server {\n        listen 80;\n        server_name _;\n\n        # User service health endpoint\n        location /api/user/healthz {\n            proxy_pass http://user-service/healthz;\n            proxy_set_header Host $host;\n            proxy_set_header X-Real-IP $remote_addr;\n        }\n\n        # Gateway API routes\n        location /api/user/ {\n            proxy_hide_header Access-Control-Allow-Origin;\n            add_header Access-Control-Allow-Origin '\''*'\'' always;\n            add_header Access-Control-Allow-Methods '\''GET, POST, PUT, DELETE, OPTIONS'\'' always;\n            add_header Access-Control-Allow-Headers '\''DNT,User-Agent,X-Requested-With,If-Modified-Since,Cache-Control,Content-Type,Range,Authorization'\'' always;\n            proxy_pass http://user-service/api/v1/;\n            proxy_set_header Host $host;\n            proxy_set_header X-Real-IP $remote_addr;\n            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n            proxy_set_header X-Forwarded-Proto $scheme;\n        }\n\n        # Event service health endpoint\n        location /api/event/healthz {\n            proxy_pass http://event-service/healthz;\n            proxy_set_header Host $host;\n            proxy_set_header X-Real-IP $remote_addr;\n        }\n\n        location /api/event/ {\n            proxy_hide_header Access-Control-Allow-Origin;\n            add_header Access-Control-Allow-Origin '\''*'\'' always;\n            add_header Access-Control-Allow-Methods '\''GET, POST, PUT, DELETE, OPTIONS'\'' always;\n            add_header Access-Control-Allow-Headers '\''DNT,User-Agent,X-Requested-With,If-Modified-Since,Cache-Control,Content-Type,Range,Authorization'\'' always;\n            proxy_pass http://event-service/api/v1/;\n            proxy_set_header Host $host;\n            proxy_set_header X-Real-IP $remote_addr;\n            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n            proxy_set_header X-Forwarded-Proto $scheme;\n        }\n\n        # Search service health endpoints\n        location /api/search/healthz {\n            proxy_pass http://search-service/healthz;\n            proxy_set_header Host $host;\n            proxy_set_header X-Real-IP $remote_addr;\n        }\n\n        location /api/search/health/ready {\n            proxy_pass http://search-service/health/ready;\n            proxy_set_header Host $host;\n            proxy_set_header X-Real-IP $remote_addr;\n        }\n\n        location /api/search/ {\n            proxy_hide_header Access-Control-Allow-Origin;\n            add_header Access-Control-Allow-Origin '\''*'\'' always;\n            add_header Access-Control-Allow-Methods '\''GET, POST, PUT, DELETE, OPTIONS'\'' always;\n            add_header Access-Control-Allow-Headers '\''DNT,User-Agent,X-Requested-With,If-Modified-Since,Cache-Control,Content-Type,Range,Authorization'\'' always;\n            proxy_pass http://search-service/api/v1/;\n            proxy_set_header Host $host;\n            proxy_set_header X-Real-IP $remote_addr;\n            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n            proxy_set_header X-Forwarded-Proto $scheme;\n        }\n\n        # Booking service health endpoint\n        location /api/booking/healthz {\n            proxy_pass http://booking-service/healthz;\n            proxy_set_header Host $host;\n            proxy_set_header X-Real-IP $remote_addr;\n        }\n\n        location /api/booking/ {\n            proxy_hide_header Access-Control-Allow-Origin;\n            add_header Access-Control-Allow-Origin '\''*'\'' always;\n            add_header Access-Control-Allow-Methods '\''GET, POST, PUT, DELETE, OPTIONS'\'' always;\n            add_header Access-Control-Allow-Headers '\''DNT,User-Agent,X-Requested-With,If-Modified-Since,Cache-Control,Content-Type,Range,Authorization'\'' always;\n            proxy_pass http://booking-service/api/v1/;\n            proxy_set_header Host $host;\n            proxy_set_header X-Real-IP $remote_addr;\n            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n            proxy_set_header X-Forwarded-Proto $scheme;\n        }\n\n        # Health endpoint\n        location /health {\n            access_log off;\n            add_header Content-Type application/json;\n            return 200 '\''{\"message\": \"BookMyEvent API Gateway\", \"status\": \"healthy\"}'\'';\n        }\n\n        # Serve frontend\n        location / {\n            proxy_pass http://frontend:80/;\n            proxy_set_header Host $host;\n            proxy_set_header X-Real-IP $remote_addr;\n            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n            proxy_set_header X-Forwarded-Proto $scheme;\n        }\n    }\n}"
  }
}'

echo "ConfigMap patched successfully"
echo "Restarting nginx gateway pods..."
kubectl rollout restart deployment/nginx-gateway -n bookmyevent
kubectl rollout status deployment/nginx-gateway -n bookmyevent

echo "Nginx configuration updated with health endpoints"
